import redis.asyncio as redis
from typing import Optional, Dict, Any
import json
import os

class DistributedCacheService:
    def __init__(self, redis_nodes: list[dict], default_ttl_seconds: int = 3600):
        """
        Initializes the DistributedCacheService with a list of Redis nodes.

        Args:
            redis_nodes: A list of dictionaries, where each dictionary
                         represents a Redis node and contains 'host' and 'port' keys.
                         Example: [{'host': 'localhost', 'port': 6379}, ...]
            default_ttl_seconds: Default time-to-live for cache entries in seconds.
        """
        if not redis_nodes:
            raise ValueError("At least one Redis node must be provided.")

        self.redis_nodes_config = redis_nodes
        self.default_ttl_seconds = default_ttl_seconds
        self.redis_cluster = None
        self._initialize_cluster()

    def _initialize_cluster(self):
        """Initializes the redis-py Cluster client."""
        startup_nodes = [
            redis.Redis(host=node['host'], port=node['port'], decode_responses=True)
            for node in self.redis_nodes_config
        ]
        self.redis_cluster = redis.RedisCluster(
            startup_nodes=startup_nodes,
            decode_responses=True,
            skip_full_coverage_check=True # Set to True if not all nodes are available during startup
        )

    async def _ensure_connection(self):
        """Ensures the connection to the Redis cluster is active."""
        try:
            await self.redis_cluster.ping()
        except redis.exceptions.RedisClusterException as e:
            print(f"Redis Cluster connection failed, attempting re-initialization: {e}")
            self._initialize_cluster()
            await self.redis_cluster.ping() # Try ping again after re-init

    async def set_sensitive_data(self, key: str, data: Dict[str, Any], ttl_seconds: Optional[int] = None) -> bool:
        """
        Stores sensitive user data in Redis with a specified TTL.
        Data is serialized to JSON before storing.

        Args:
            key: The unique key for the data (e.g., session_token_id, user_id:api_key).
            data: A dictionary containing the sensitive data.
            ttl_seconds: Time-to-live for this specific entry in seconds.
                         If None, uses the default_ttl_seconds.

        Returns:
            True if the data was set successfully, False otherwise.
        """
        await self._ensure_connection()
        try:
            serialized_data = json.dumps(data)
            ttl = ttl_seconds if ttl_seconds is not None else self.default_ttl_seconds
            result = await self.redis_cluster.set(key, serialized_data, ex=ttl)
            return bool(result)
        except Exception as e:
            print(f"Error setting data for key '{key}': {e}")
            return False

    async def get_sensitive_data(self, key: str) -> Optional[Dict[str, Any]]:
        """
        Retrieves sensitive user data from Redis.
        Data is deserialized from JSON.

        Args:
            key: The unique key for the data.

        Returns:
            The deserialized dictionary if found, None otherwise.
        """
        await self._ensure_connection()
        try:
            serialized_data = await self.redis_cluster.get(key)
            if serialized_data:
                return json.loads(serialized_data)
            return None
        except Exception as e:
            print(f"Error getting data for key '{key}': {e}")
            return None

    async def delete_sensitive_data(self, key: str) -> int:
        """
        Deletes sensitive user data from Redis.

        Args:
            key: The unique key for the data to delete.

        Returns:
            The number of keys deleted (0 or 1).
        """
        await self._ensure_connection()
        try:
            return await self.redis_cluster.delete(key)
        except Exception as e:
            print(f"Error deleting data for key '{key}': {e}")
            return 0

    async def close(self):
        """Closes the connection to the Redis cluster."""
        if self.redis_cluster:
            await self.redis_cluster.close()

